package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request and logs analytics data.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search event with timestamp
	// In a real-world scenario, this might send data to an external analytics service.
	log.Printf("[Analytics] Search performed | Keyword: %q | Time: %s | IP: %s",
		keyword,
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
	)

	// HTML escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct the HTML response
	// Requirement: Display the user's search keyword in the page title area
	htmlResponse := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .results { margin-top: 20px; color: #333; }
    </style>
</head>
<body>
    <header>
        <h1>Online Store</h1>
    </header>
    <main>
        <h2>Search Results: %s</h2>
        <div class="results">
            <p>No products found for demonstration.</p>
        </div>
    </main>
</body>
</html>`, safeKeyword)

	// Write the response to the client
	fmt.Fprint(w, htmlResponse)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server listening on port %s...", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

