package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameters, logs it for analytics,
// and returns an HTML page with the search results header.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log the search query to standard output.
	// In a production environment, this might be sent to an analytics service.
	if keyword != "" {
		log.Printf("Search Analytics: User searched for keyword '%s'", keyword)
	} else {
		log.Println("Search Analytics: User performed an empty search")
	}

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent HTML injection attacks
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// The requirement specifies the format: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Product listings would appear here.</p>
</body>
</html>`, escapedKeyword)

	// Write the HTML content to the response
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := "8080"
	fmt.Printf("Server is running on http://localhost:%s/search\n", port)
	if err := http.ListenAndServe(":"+port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

