package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter, logs the analytics event,
// and returns an HTML page with the search results title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search event to standard output
	// In a real-world scenario, this might send data to a service like Google Analytics
	log.Printf("Analytics: Search performed for keyword '%s' from IP %s", keyword, r.RemoteAddr)

	// Escape the keyword to prevent Cross-Site Scripting (XSS) attacks
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        h1 { color: #333; }
        h2 { color: #007BFF; }
    </style>
</head>
<body>
    <h1>Product Search</h1>
    <h2>Search Results: %s</h2>
    <div class="results">
        <p>No products found matching your criteria.</p>
        <!-- In a real application, product items would be listed here -->
    </div>
</body>
</html>`, escapedKeyword)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write the HTTP status code and the HTML content
	w.WriteHeader(http.StatusOK)
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the "/search" path
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server is running on http://localhost%s", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

