import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the URL query, logs the search event (analytics),
// and renders an HTML page displaying the search results title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log the search request.
	// In a real-world scenario, this might involve sending data to an external analytics system.
	// Here, we use the standard log package to record the event.
	log.Printf("Analytics: Search performed with keyword '%s' from IP %s", keyword, r.RemoteAddr)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS) attacks
	safeKeyword := html.EscapeString(keyword)

	// Build the HTML response
	// The requirement specifically asks for the format: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
</head>
<body>
    <header>
        <h1>Product Store</h1>
    </header>
    <main>
        <!-- Required Title Format -->
        <h2>Search Results: %s</h2>

        <div class="results">
            <p>Displaying results for: <strong>%s</strong></p>
            <!-- Placeholder for product items -->
        </div>
    </main>
</body>
</html>`, safeKeyword, safeKeyword)

	// Write the HTML content to the response writer
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the HandleProductSearch function for the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Define the server port
	port := ":8080"

	fmt.Printf("Server is running on http://localhost%s\n", port)
	fmt.Println("Open your browser and visit: http://localhost:8080/search?keyword=golang")

	// Start the HTTP server
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

