package main

import (
	"fmt"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameter, logs it for analytics,
// and returns an HTML page with the search results title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log the search request to standard output
	// In a real-world scenario, this might be sent to a dedicated analytics service.
	log.Printf("Search analytics: User searched for keyword '%s' from IP %s", keyword, r.RemoteAddr)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Construct the HTML response
	// We use fmt.Sprintf to inject the keyword into the H2 tag as requested.
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        h2 { color: #333; }
    </style>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Below are the products matching your query.</p>
    <!-- Product list would go here -->
</body>
</html>`, keyword)

	// Write the content to the response writer
	if _, err := fmt.Fprint(w, htmlContent); err != nil {
		log.Printf("Error writing response: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the HandleProductSearch function for the "/search" path
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

