package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// trackSearch simulates an analytics event recording the search keyword.
func trackSearch(keyword string) {
	// In a real application, this might send data to an external analytics service.
	// Here, we simply log the event to standard output to demonstrate the logic.
	log.Printf("Analytics Event: User searched for keyword '%s'", keyword)
}

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameters, records an analytics event,
// and returns an HTML page displaying the search results title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the 'keyword' query parameter.
	keyword := r.URL.Query().Get("keyword")

	// Record analytics for this search.
	trackSearch(keyword)

	// Set the Content-Type header to HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS (Cross-Site Scripting) attacks.
	safeKeyword := html.EscapeString(keyword)

	// Construct the HTML response.
	// The requirement is to display: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Product listings would appear here.</p>
</body>
</html>`, safeKeyword)

	// Write the HTML content to the response writer.
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the "/search" route.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server.
	port := ":8080"
	fmt.Printf("Server is running on http://localhost%s\n", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

