package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter, logs it for analytics,
// and returns an HTML page displaying the search results header.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search request details
	// In a real-world scenario, this might be sent to an external analytics service.
	// Here, we log to standard output.
	log.Printf("[Analytics] Search performed | Keyword: %q | Time: %s | IP: %s",
		keyword,
		time.Now().Format(time.RFC3339),
		r.RemoteAddr,
	)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// The requirement specifically asks for: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .search-header { color: #333; border-bottom: 2px solid #eee; padding-bottom: 10px; }
    </style>
</head>
<body>
    <div class="search-header">
        <h2>Search Results: %s</h2>
    </div>
    <div class="content">
        <p>Displaying results for keyword: <strong>%s</strong></p>
        <!-- Product items would be rendered here -->
    </div>
</body>
</html>`, safeKeyword, safeKeyword)

	// Write the HTML content to the response writer
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the HandleProductSearch function to the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Define the server port
	serverPort := ":8080"

	// Start the HTTP server
	log.Printf("Server is listening on http://localhost%s", serverPort)
	if err := http.ListenAndServe(serverPort, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

