// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter, logs the search for analytics,
// and returns an HTML response with the search results header.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Retrieve the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search request details
	// In a real-world scenario, this might be sent to a metrics system like Prometheus or a database.
	log.Printf("Search Analytics - Keyword: '%s' | UserAgent: '%s' | IP: '%s'", keyword, r.UserAgent(), r.RemoteAddr)

	// 3. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Sanitize the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// 5. Construct the HTML response
	// The requirement is to display: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .container { max-width: 800px; margin: 0 auto; }
        .status { color: #666; font-style: italic; }
    </style>
</head>
<body>
    <div class="container">
        <h1>Product Catalog</h1>
        <h2>Search Results: %s</h2>
        <p class="status">Analytics recorded for search term.</p>
        <hr>
        <p>Product list would go here...</p>
    </div>
</body>
</html>`, safeKeyword)

	// 6. Write the response to the client
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the "/search" path
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server starting on port %s...", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

