package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameters, logs the analytics event,
// and returns an HTML response with the search results header.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search request to standard output
	// In a production environment, this might be sent to a dedicated analytics service.
	log.Printf("Search Analytics: Keyword='%s', IP=%s, UserAgent='%s'", keyword, r.RemoteAddr, r.UserAgent())

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Sanitize the keyword to prevent XSS (Cross-Site Scripting) attacks
	safeKeyword := html.EscapeString(keyword)

	// Write the HTML response body
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", safeKeyword)
}

func main() {
	// Register the handler for the /search route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	log.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

