	"time"
)

// AnalyticsRecorder simulates an analytics system to track search events.
type AnalyticsRecorder struct{}

// RecordSearch logs the search keyword and timestamp to standard output.
// In a production environment, this might send data to an external service.
func (a *AnalyticsRecorder) RecordSearch(keyword string) {
	log.Printf("[Analytics] Search performed | Keyword: %q | Timestamp: %s", keyword, time.Now().Format(time.RFC3339))
}

var analytics = &AnalyticsRecorder{}

// HandleProductSearch handles the product search request.
// It retrieves the keyword, records the analytics, and returns an HTML page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Retrieve the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// 2. Record the search event for analytics
	analytics.RecordSearch(keyword)

	// 3. Sanitize the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// 4. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 5. Construct the HTML response
	// The requirement is to display the user's search keyword in the page title area.
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        h2 { color: #333; border-bottom: 2px solid #eee; padding-bottom: 10px; }
    </style>
</head>
<body>
    <h2>Search Results: %s</h2>
    <div class="content">
        <p>Displaying results for: <strong>%s</strong></p>
        <!-- Product items would be listed here -->
        <ul>
            <li>Product A</li>
            <li>Product B</li>
        </ul>
    </div>
</body>
</html>`, safeKeyword, safeKeyword)

	// 6. Write the response body
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Server is listening on http://localhost%s", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

