package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter, logs it for analytics,
// and returns an HTML page with the search results header.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log the search keyword to the server console
	// In a real-world scenario, this might be sent to a metrics collector.
	log.Printf("Analytics: Search performed with keyword '%s'", keyword)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks before embedding in HTML
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Product list would be displayed here.</p>
</body>
</html>`, escapedKeyword)

	// Write the HTML content to the response writer
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server starting on port %s...", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

