// HandleProductSearch handles the product search request with analytics support.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// 1. Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// 2. Analytics Support: Log the search keyword
	// In a real-world scenario, this might involve sending an event to an external analytics service
	// or writing to a database. Here we use standard logging for demonstration.
	log.Printf("Analytics: Search performed for keyword: %s", keyword)

	// 3. Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// 4. Construct the HTML response body
	// We use fmt.Sprintf to inject the keyword safely into the HTML structure.
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product listings would go here -->
</body>
</html>`, keyword)

	// 5. Write the response
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler for the "/search" route
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server is running on http://localhost%s", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

